  1→/**
  2→ * FlowDiagram — DOM/CSS conversation flow visualization.
  3→ *
  4→ * Renders a vertical flow of user→agent→tool cards grouped by phase.
  5→ * Tool calls are shown as compact colored chips inside agent cards,
  6→ * eliminating messy fan-out arrows. Dependencies are revealed on hover
  7→ * via highlight rings on related tools.
  8→ */
  9→
 10→import { useState, useMemo, useCallback } from "react";
 11→import type { Step, FlowData } from "../../types";
 12→import { useTooltip, Tooltip } from "../analysis/tooltip";
 13→import {
 14→  computeFlow,
 15→  type FlowPhaseGroup,
 16→  type FlowToolChip,
 17→} from "./flow-layout";
 18→
 19→interface FlowDiagramProps {
 20→  steps: Step[];
 21→  flowData: FlowData;
 22→}
 23→
 24→const CATEGORY_STYLE: Record<string, { bg: string; ring: string; text: string; label: string }> = {
 25→  file_read: { bg: "bg-blue-500/20", ring: "ring-blue-400/60", text: "text-blue-300", label: "read" },
 26→  file_write: { bg: "bg-emerald-500/20", ring: "ring-emerald-400/60", text: "text-emerald-300", label: "write" },
 27→  shell: { bg: "bg-amber-500/20", ring: "ring-amber-400/60", text: "text-amber-300", label: "shell" },
 28→  search: { bg: "bg-sky-500/20", ring: "ring-sky-400/60", text: "text-sky-300", label: "search" },
 29→  web: { bg: "bg-orange-500/20", ring: "ring-orange-400/60", text: "text-orange-300", label: "web" },
 30→  agent: { bg: "bg-violet-500/20", ring: "ring-violet-400/60", text: "text-violet-300", label: "agent" },
 31→  task: { bg: "bg-rose-500/20", ring: "ring-rose-400/60", text: "text-rose-300", label: "task" },
 32→  other: { bg: "bg-zinc-500/20", ring: "ring-zinc-400/60", text: "text-zinc-400", label: "other" },
 33→};
 34→
 35→const PHASE_STYLE: Record<string, { border: string; label: string; dot: string; bg: string }> = {
 36→  exploration: { border: "border-l-blue-400", label: "text-blue-400", dot: "bg-blue-400", bg: "bg-blue-500/[0.03]" },
 37→  implementation: { border: "border-l-emerald-400", label: "text-emerald-400", dot: "bg-emerald-400", bg: "bg-emerald-500/[0.03]" },
 38→  debugging: { border: "border-l-red-400", label: "text-red-400", dot: "bg-red-400", bg: "bg-red-500/[0.03]" },
 39→  verification: { border: "border-l-amber-400", label: "text-amber-400", dot: "bg-amber-400", bg: "bg-amber-500/[0.03]" },
 40→  planning: { border: "border-l-violet-400", label: "text-violet-400", dot: "bg-violet-400", bg: "bg-violet-500/[0.03]" },
 41→  mixed: { border: "border-l-zinc-500", label: "text-zinc-400", dot: "bg-zinc-500", bg: "bg-zinc-500/[0.02]" },
 42→};
 43→
 44→const RELATION_LABELS: Record<string, string> = {
 45→  read_before_write: "read \u2192 write",
 46→  search_then_read: "search \u2192 read",
 47→  error_retry: "retry",
 48→};
 49→
 50→export function FlowDiagram({ steps, flowData }: FlowDiagramProps) {
 51→  const { tip, show, move, hide } = useTooltip();
 52→  const [hoveredToolId, setHoveredToolId] = useState<string | null>(null);
 53→
 54→  const result = useMemo(
 55→    () => computeFlow(steps, flowData.tool_graph, flowData.phase_segments),
 56→    [steps, flowData]
 57→  );
 58→
 59→  // Bidirectional dependency lookup for hover highlighting
 60→  const relatedTools = useMemo(() => {
 61→    const map = new Map<string, Set<string>>();
 62→    for (const [sourceId, deps] of result.dependencies) {
 63→      for (const dep of deps) {
 64→        if (!map.has(sourceId)) map.set(sourceId, new Set());
 65→        map.get(sourceId)!.add(dep.targetToolCallId);
 66→        if (!map.has(dep.targetToolCallId)) map.set(dep.targetToolCallId, new Set());
 67→        map.get(dep.targetToolCallId)!.add(sourceId);
 68→      }
 69→    }
 70→    return map;
 71→  }, [result.dependencies]);
 72→
 73→  // Dependency label for a highlighted tool
 74→  const depLabels = useMemo(() => {
 75→    const map = new Map<string, string>();
 76→    for (const [sourceId, deps] of result.dependencies) {
 77→      for (const dep of deps) {
 78→        const label = RELATION_LABELS[dep.relation] || dep.relation;
 79→        map.set(`${sourceId}->${dep.targetToolCallId}`, label);
 80→        map.set(`${dep.targetToolCallId}->${sourceId}`, label);
 81→      }
 82→    }
 83→    return map;
 84→  }, [result.dependencies]);
 85→
 86→  const isHighlighted = useCallback(
 87→    (toolCallId: string): boolean => {
 88→      if (!hoveredToolId) return false;
 89→      if (toolCallId === hoveredToolId) return true;
 90→      return relatedTools.get(hoveredToolId)?.has(toolCallId) || false;
 91→    },
 92→    [hoveredToolId, relatedTools]
 93→  );
 94→
 95→  const getDepLabel = useCallback(
 96→    (toolCallId: string): string | null => {
 97→      if (!hoveredToolId || toolCallId === hoveredToolId) return null;
 98→      return depLabels.get(`${hoveredToolId}->${toolCallId}`) || null;
 99→    },
100→    [hoveredToolId, depLabels]
101→  );
102→
103→  return (
104→    <div className="max-w-3xl mx-auto pb-8">
105→      {result.phases.map((phase, phaseIdx) => (
106→        <div key={phaseIdx}>
107→          <PhaseSection phase={phase}>
108→            {phase.cards.map((card, cardIdx) => (
109→              <div key={card.data.id}>
110→                {cardIdx > 0 && <Connector />}
111→                {card.type === "user" ? (
112→                  <UserCard
113→                    label={card.data.label}
114→                    detail={card.data.detail}
115→                    onHover={show}
116→                    onMove={move}
117→                    onLeave={hide}
118→                  />
119→                ) : (
120→                  <AgentCard
121→                    label={card.data.label}
122→                    detail={card.data.detail}
123→                    tools={card.data.tools}
124→                    hoveredToolId={hoveredToolId}
125→                    onToolEnter={setHoveredToolId}
126→                    onToolLeave={() => setHoveredToolId(null)}
127→                    isHighlighted={isHighlighted}
128→                    getDepLabel={getDepLabel}
129→                    onHover={show}
130→                    onMove={move}
131→                    onLeave={hide}
132→                  />
133→                )}
134→              </div>
135→            ))}
136→          </PhaseSection>
137→          {/* Connector between phase sections */}
138→          {phaseIdx < result.phases.length - 1 && (
139→            <div className="flex items-center pl-6 py-1">
140→              <div className="flex flex-col items-center">
141→                <div className="w-px h-2 bg-zinc-700/30" />
142→                <div className="w-1 h-1 rounded-full bg-zinc-600/40" />
143→                <div className="w-px h-2 bg-zinc-700/30" />
144→              </div>
145→            </div>
146→          )}
147→        </div>
148→      ))}
149→      <Tooltip state={tip} />
150→    </div>
151→  );
152→}
153→
154→function PhaseSection({
155→  phase,
156→  children,
157→}: {
158→  phase: FlowPhaseGroup;
159→  children: React.ReactNode;
160→}) {
161→  const style = PHASE_STYLE[phase.phase] || PHASE_STYLE.mixed;
162→
163→  return (
164→    <div className={`rounded-lg ${style.bg}`}>
165→      <div className={`border-l-[3px] ${style.border} pl-5 pr-3 py-4`}>
166→        {/* Phase header */}
167→        <div className="flex items-center gap-2.5 mb-4">
168→          <span className={`w-2.5 h-2.5 rounded-full ${style.dot} ring-2 ring-current/10`} />
169→          <span className={`text-[11px] font-bold uppercase tracking-[0.14em] ${style.label}`}>
170→            {phase.phase}
171→          </span>
172→          <span className="text-[10px] text-zinc-600 font-medium">
173→            {phase.cards.length} step{phase.cards.length !== 1 ? "s" : ""}
174→          </span>
175→        </div>
176→        <div>{children}</div>
177→      </div>
178→    </div>
179→  );
180→}
181→
182→function Connector() {
183→  return (
184→    <div className="flex items-center justify-center py-1.5">
185→      <div className="flex flex-col items-center">
186→        <div className="w-px h-2.5 bg-zinc-700/40" />
187→        <div className="w-[5px] h-[5px] rounded-full border border-zinc-600/60 bg-zinc-800" />
188→        <div className="w-px h-2.5 bg-zinc-700/40" />
189→      </div>
190→    </div>
191→  );
192→}
193→
194→function UserCard({
195→  label,
196→  detail,
197→  onHover,
198→  onMove,
199→  onLeave,
200→}: {
201→  label: string;
202→  detail: string;
203→  onHover: (e: React.MouseEvent, content: string) => void;
204→  onMove: (e: React.MouseEvent) => void;
205→  onLeave: () => void;
206→}) {
207→  return (
208→    <div
209→      className="group relative rounded-lg border border-indigo-500/30 bg-indigo-950/30 hover:border-indigo-400/50 hover:bg-indigo-950/40 transition-all"
210→      onMouseEnter={(e) => onHover(e, detail)}
211→      onMouseMove={onMove}
212→      onMouseLeave={onLeave}
213→    >
214→      <div className="px-4 py-3 flex items-start gap-3">
215→        <span className="shrink-0 mt-0.5 w-6 h-6 rounded-md bg-indigo-500/25 border border-indigo-400/20 flex items-center justify-center">
216→          <svg className="w-3 h-3 text-indigo-300" viewBox="0 0 16 16" fill="currentColor">
217→            <path d="M8 8a3 3 0 1 0 0-6 3 3 0 0 0 0 6zm2-3a2 2 0 1 1-4 0 2 2 0 0 1 4 0zm4 8c0 1-1 1-1 1H3s-1 0-1-1 1-4 6-4 6 3 6 4zm-1-.004c-.001-.246-.154-.986-.832-1.664C11.516 10.68 10.289 10 8 10c-2.29 0-3.516.68-4.168 1.332-.678.678-.83 1.418-.832 1.664h10z"/>
218→          </svg>
219→        </span>
220→        <p className="text-[13px] leading-relaxed text-indigo-100 min-w-0 break-words">
221→          {label}
222→        </p>
223→      </div>
224→    </div>
225→  );
226→}
227→
228→function AgentCard({
229→  label,
230→  detail,
231→  tools,
232→  hoveredToolId,
233→  onToolEnter,
234→  onToolLeave,
235→  isHighlighted,
236→  getDepLabel,
237→  onHover,
238→  onMove,
239→  onLeave,
240→}: {
241→  label: string;
242→  detail: string;
243→  tools: FlowToolChip[];
244→  hoveredToolId: string | null;
245→  onToolEnter: (id: string) => void;
246→  onToolLeave: () => void;
247→  isHighlighted: (toolCallId: string) => boolean;
248→  getDepLabel: (toolCallId: string) => string | null;
249→  onHover: (e: React.MouseEvent, content: string) => void;
250→  onMove: (e: React.MouseEvent) => void;
251→  onLeave: () => void;
252→}) {
253→  // Group tools by category for summary display
254→  const grouped = useMemo(() => {
255→    const map = new Map<string, FlowToolChip[]>();
256→    for (const tool of tools) {
257→      const list = map.get(tool.category) || [];
258→      list.push(tool);
259→      map.set(tool.category, list);
260→    }
261→    const order = ["file_read", "search", "file_write", "shell", "web", "agent", "task", "other"];
262→    return [...map.entries()].sort(
263→      ([a], [b]) => (order.indexOf(a) === -1 ? 99 : order.indexOf(a)) - (order.indexOf(b) === -1 ? 99 : order.indexOf(b))
264→    );
265→  }, [tools]);
266→
267→  return (
268→    <div className="rounded-lg border border-cyan-500/20 bg-cyan-950/20 hover:border-cyan-400/35 transition-colors">
269→      {/* Agent message */}
270→      <div
271→        className="px-4 py-3 flex items-start gap-3"
272→        onMouseEnter={(e) => onHover(e, detail)}
273→        onMouseMove={onMove}
274→        onMouseLeave={onLeave}
275→      >
276→        <span className="shrink-0 mt-0.5 w-6 h-6 rounded-md bg-cyan-500/20 border border-cyan-400/15 flex items-center justify-center">
277→          <svg className="w-3 h-3 text-cyan-300" viewBox="0 0 16 16" fill="currentColor">
278→            <path d="M6 12.5a.5.5 0 0 1 .5-.5h3a.5.5 0 0 1 0 1h-3a.5.5 0 0 1-.5-.5zM3 8.062C3 6.76 4.235 5.765 5.53 5.886a26.58 26.58 0 0 0 4.94 0C11.765 5.765 13 6.76 13 8.062v1.157a.933.933 0 0 1-.765.935c-.845.147-2.34.346-4.235.346-1.895 0-3.39-.2-4.235-.346A.933.933 0 0 1 3 9.219V8.062zm4.542-.827a.25.25 0 0 0-.217.068l-.92.9a25.14 25.14 0 0 1-1.871-.183.25.25 0 0 0-.068.495c.55.076 1.232.149 2.02.193a.25.25 0 0 0 .189-.071l.754-.736.847 1.71a.25.25 0 0 0 .404.062l.932-.97a25.286 25.286 0 0 0 1.922-.188.25.25 0 0 0-.068-.495c-.538.074-1.207.145-1.98.189a.25.25 0 0 0-.166.076l-.754.785-.842-1.7a.25.25 0 0 0-.182-.135z"/>
279→            <path d="M8.5 1.866a1 1 0 1 0-1 0V3h-2A4.5 4.5 0 0 0 1 7.5V8a1 1 0 0 0-1 1v2a1 1 0 0 0 1 1v1a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2v-1a1 1 0 0 0 1-1V9a1 1 0 0 0-1-1v-.5A4.5 4.5 0 0 0 10.5 3h-2V1.866zM14 7.5V13a1 1 0 0 1-1 1H3a1 1 0 0 1-1-1V7.5A3.5 3.5 0 0 1 5.5 4h5A3.5 3.5 0 0 1 14 7.5z"/>
280→          </svg>
281→        </span>
282→        <p className="text-[13px] leading-relaxed text-cyan-100/85 min-w-0 break-words">
283→          {label}
284→        </p>
285→      </div>
286→
287→      {/* Tool calls section */}
288→      {tools.length > 0 && (
289→        <div className="border-t border-cyan-500/10 mx-3 px-1 py-2.5">
290→          {/* Header with count and category breakdown */}
291→          <div className="flex items-center gap-1.5 mb-2 px-1">
292→            <span className="text-[10px] font-semibold text-zinc-500 uppercase tracking-wider">
293→              {tools.length} tool{tools.length !== 1 ? "s" : ""}
294→            </span>
295→            <span className="text-zinc-700 text-[10px]">\u00b7</span>
296→            <div className="flex gap-1.5">
297→              {grouped.map(([cat, items]) => {
298→                const catStyle = CATEGORY_STYLE[cat] || CATEGORY_STYLE.other;
299→                return (
300→                  <span
301→                    key={cat}
302→                    className={`inline-flex items-center gap-1 text-[10px] ${catStyle.text}`}
303→                    title={`${items.length} ${cat.replace(/_/g, " ")}`}
304→                  >
305→                    <span className={`w-2 h-2 rounded-sm ${catStyle.bg} border border-current/20`} />
306→                    <span className="opacity-70">{catStyle.label}</span>
307→                    <span className="font-mono font-semibold">{items.length}</span>
308→                  </span>
309→                );
310→              })}
311→            </div>
312→          </div>
313→          {/* Tool pills */}
314→          <div className="flex flex-wrap gap-1.5 px-1">
315→            {tools.map((tool) => (
316→              <ToolChip
317→                key={tool.id}
318→                tool={tool}
319→                highlighted={isHighlighted(tool.toolCallId)}
320→                depLabel={getDepLabel(tool.toolCallId)}
321→                isAnyHovered={!!hoveredToolId}
322→                onEnter={() => onToolEnter(tool.toolCallId)}
323→                onLeave={onToolLeave}
324→                onHover={onHover}
325→                onMove={onMove}
326→                onHoverLeave={onLeave}
327→              />
328→            ))}
329→          </div>
330→        </div>
331→      )}
332→    </div>
333→  );
334→}
335→
336→function ToolChip({
337→  tool,
338→  highlighted,
339→  depLabel,
340→  isAnyHovered,
341→  onEnter,
342→  onLeave,
343→  onHover,
344→  onMove,
345→  onHoverLeave,
346→}: {
347→  tool: FlowToolChip;
348→  highlighted: boolean;
349→  depLabel: string | null;
350→  isAnyHovered: boolean;
351→  onEnter: () => void;
352→  onLeave: () => void;
353→  onHover: (e: React.MouseEvent, content: string) => void;
354→  onMove: (e: React.MouseEvent) => void;
355→  onHoverLeave: () => void;
356→}) {
357→  const style = CATEGORY_STYLE[tool.category] || CATEGORY_STYLE.other;
358→  const dimmed = isAnyHovered && !highlighted;
359→
360→  return (
361→    <span
362→      className={`
363→        relative inline-flex items-center gap-1.5 px-2.5 py-1 rounded-md text-[11px] font-mono
364→        border transition-all duration-150 cursor-default
365→        ${style.bg} ${style.text}
366→        ${highlighted ? `ring-2 ${style.ring} border-transparent brightness-125` : "border-transparent"}
367→        ${dimmed ? "opacity-25" : "opacity-100"}
368→        hover:opacity-100 hover:brightness-125
369→      `}
370→      onMouseEnter={(e) => {
371→        onEnter();
372→        onHover(e, tool.detail);
373→      }}
374→      onMouseMove={onMove}
375→      onMouseLeave={() => {
376→        onLeave();
377→        onHoverLeave();
378→      }}
379→    >
380→      {tool.name}
381→      {depLabel && (
382→        <span className="absolute -top-2.5 left-1/2 -translate-x-1/2 px-1.5 py-px rounded-full text-[8px] font-sans font-bold bg-zinc-900 border border-zinc-500 text-zinc-200 whitespace-nowrap shadow-lg">
383→          {depLabel}
384→        </span>
385→      )}
386→    </span>
387→  );
388→}
