  1→/**
  2→ * Flow layout engine — converts Steps + FlowData into structured card data.
  3→ *
  4→ * Produces phase-grouped cards (user prompts + agent responses with embedded
  5→ * tool chips) and a dependency map for hover highlighting. No x/y positioning
  6→ * needed — the FlowDiagram component uses DOM/CSS layout.
  7→ */
  8→
  9→import type { Step, ToolDependencyGraph, PhaseSegment } from "../../types";
 10→import { extractMessageText } from "../../utils";
 11→
 12→export interface FlowToolChip {
 13→  id: string;
 14→  name: string;
 15→  category: string;
 16→  detail: string;
 17→  toolCallId: string;
 18→}
 19→
 20→export interface FlowAgentCardData {
 21→  id: string;
 22→  label: string;
 23→  detail: string;
 24→  stepIndex: number;
 25→  tools: FlowToolChip[];
 26→}
 27→
 28→export interface FlowUserCardData {
 29→  id: string;
 30→  label: string;
 31→  detail: string;
 32→  stepIndex: number;
 33→}
 34→
 35→export type FlowCard =
 36→  | { type: "user"; data: FlowUserCardData }
 37→  | { type: "agent"; data: FlowAgentCardData };
 38→
 39→export interface FlowPhaseGroup {
 40→  phase: string;
 41→  cards: FlowCard[];
 42→}
 43→
 44→export interface ToolRelation {
 45→  targetToolCallId: string;
 46→  relation: string;
 47→  sharedResource?: string;
 48→}
 49→
 50→export interface FlowResult {
 51→  phases: FlowPhaseGroup[];
 52→  dependencies: Map<string, ToolRelation[]>;
 53→}
 54→
 55→const LABEL_MAX_LENGTH = 120;
 56→
 57→const TOOL_CATEGORY_MAP: Record<string, string> = {
 58→  Read: "file_read",
 59→  read_file: "file_read",
 60→  cat: "file_read",
 61→  Glob: "search",
 62→  glob: "search",
 63→  Grep: "search",
 64→  grep: "search",
 65→  find: "search",
 66→  Edit: "file_write",
 67→  Write: "file_write",
 68→  write_file: "file_write",
 69→  NotebookEdit: "file_write",
 70→  MultiEdit: "file_write",
 71→  apply_patch: "file_write",
 72→  "apply-patch": "file_write",
 73→  Bash: "shell",
 74→  bash: "shell",
 75→  shell: "shell",
 76→  execute_command: "shell",
 77→  WebSearch: "web",
 78→  WebFetch: "web",
 79→  web_search: "web",
 80→  Agent: "agent",
 81→  Task: "agent",
 82→  Skill: "agent",
 83→  TaskCreate: "task",
 84→  TaskUpdate: "task",
 85→  TaskList: "task",
 86→  TaskGet: "task",
 87→};
 88→
 89→function truncateLabel(text: string, max: number): string {
 90→  if (text.length <= max) return text;
 91→  return text.slice(0, max - 1) + "\u2026";
 92→}
 93→
 94→function formatToolArgs(args: unknown): string {
 95→  if (!args) return "";
 96→  if (typeof args === "string") return args.slice(0, 300);
 97→  try {
 98→    return JSON.stringify(args, null, 2).slice(0, 400);
 99→  } catch {
100→    return String(args).slice(0, 300);
101→  }
102→}
103→
104→/** Build structured flow data from steps and analysis results. */
105→export function computeFlow(
106→  steps: Step[],
107→  toolGraph: ToolDependencyGraph | null,
108→  phases: PhaseSegment[]
109→): FlowResult {
110→  const cards = buildCards(steps);
111→  const phaseGroups = assignCardsToPhases(cards, phases);
112→  const dependencies = buildDependencyMap(toolGraph);
113→  return { phases: phaseGroups, dependencies };
114→}
115→
116→function buildCards(steps: Step[]): FlowCard[] {
117→  const cards: FlowCard[] = [];
118→  let globalStepIdx = 0;
119→
120→  for (const step of steps) {
121→    const stepIdx = globalStepIdx++;
122→
123→    if (step.source === "user") {
124→      const text = extractMessageText(step.message);
125→      if (!text) continue;
126→      cards.push({
127→        type: "user",
128→        data: {
129→          id: `user-${step.step_id}`,
130→          label: truncateLabel(text, LABEL_MAX_LENGTH),
131→          detail: text,
132→          stepIndex: stepIdx,
133→        },
134→      });
135→    }
136→
137→    if (step.source === "agent") {
138→      const text = extractMessageText(step.message);
139→      const hasTools = step.tool_calls.length > 0;
140→      if (!text && !hasTools) continue;
141→
142→      const tools: FlowToolChip[] = step.tool_calls.map((tc) => ({
143→        id: `tool-${tc.tool_call_id}`,
144→        name: tc.function_name,
145→        category: TOOL_CATEGORY_MAP[tc.function_name] || "other",
146→        detail: `${tc.function_name}\n${formatToolArgs(tc.arguments)}`,
147→        toolCallId: tc.tool_call_id,
148→      }));
149→
150→      cards.push({
151→        type: "agent",
152→        data: {
153→          id: `agent-${step.step_id}`,
154→          label: text ? truncateLabel(text, LABEL_MAX_LENGTH) : "Agent processing\u2026",
155→          detail: text || "(tool calls only)",
156→          stepIndex: stepIdx,
157→          tools,
158→        },
159→      });
160→    }
161→  }
162→
163→  return cards;
164→}
165→
166→function assignCardsToPhases(
167→  cards: FlowCard[],
168→  phases: PhaseSegment[]
169→): FlowPhaseGroup[] {
170→  if (phases.length === 0) {
171→    return cards.length > 0 ? [{ phase: "mixed", cards }] : [];
172→  }
173→
174→  const groups: FlowPhaseGroup[] = [];
175→  const assignedIndices = new Set<number>();
176→
177→  for (const seg of phases) {
178→    const segCards = cards.filter((c) => {
179→      const idx = c.data.stepIndex;
180→      return idx >= seg.start_index && idx <= seg.end_index;
181→    });
182→    if (segCards.length > 0) {
183→      groups.push({ phase: seg.phase, cards: segCards });
184→      segCards.forEach((c) => assignedIndices.add(c.data.stepIndex));
185→    }
186→  }
187→
188→  // Unassigned cards go into "mixed"
189→  const uncovered = cards.filter((c) => !assignedIndices.has(c.data.stepIndex));
190→  if (uncovered.length > 0) {
191→    groups.push({ phase: "mixed", cards: uncovered });
192→  }
193→
194→  return groups;
195→}
196→
197→function buildDependencyMap(
198→  toolGraph: ToolDependencyGraph | null
199→): Map<string, ToolRelation[]> {
200→  const map = new Map<string, ToolRelation[]>();
201→  if (!toolGraph) return map;
202→
203→  for (const edge of toolGraph.edges) {
204→    if (edge.relation === "sequential") continue;
205→    const existing = map.get(edge.source_tool_call_id) || [];
206→    existing.push({
207→      targetToolCallId: edge.target_tool_call_id,
208→      relation: edge.relation,
209→      sharedResource: edge.shared_resource || undefined,
210→    });
211→    map.set(edge.source_tool_call_id, existing);
212→  }
213→
214→  return map;
215→}
