 50→  const isSharedView = !!sharedTrajectories;
 51→
 52→  const MIN_PROMPT_NAV_WIDTH = 160;
 53→  const MAX_PROMPT_NAV_WIDTH = 400;
 54→
 55→  const handlePromptNavResize = useCallback((delta: number) => {
 56→    setPromptNavWidth((w) =>
 57→      Math.min(MAX_PROMPT_NAV_WIDTH, Math.max(MIN_PROMPT_NAV_WIDTH, w + delta))
 58→    );
 59→  }, []);
 60→
 61→  useEffect(() => {
 62→    setActiveStepId(null);
 63→    setSessionCost(null);
 64→    setFlowData(null);
 65→    setViewMode("timeline");
 66→
 67→    // When rendering shared data, skip the API fetch
 68→    if (sharedTrajectories) {
 69→      setTrajectories(sharedTrajectories);
 70→      setLoading(false);
 71→      return;
 72→    }
 73→
 74→    setLoading(true);
 75→    setError("");
 76→    setTrajectories([]);
 77→
 78→    fetchWithToken(`/api/sessions/${sessionId}`)
 79→      .then((res) => {
 80→        if (!res.ok) throw new Error(`Failed to load session: ${res.status}`);
 81→        return res.json();
 82→      })
 83→      .then((data: Trajectory[]) => {
 84→        setTrajectories(data);
 85→      })
 86→      .catch((err: Error) => setError(err.message))
 87→      .finally(() => setLoading(false));
 88→  }, [sessionId, fetchWithToken, sharedTrajectories]);
 89→
 90→  // Fetch session analytics for cost estimation (non-blocking, skip for shared views)
 91→  useEffect(() => {
