 97→      })
 98→      .catch(() => {});
 99→  }, [sessionId, loading, fetchWithToken]);
100→
101→  // Fetch flow data lazily when user toggles to flow view
102→  useEffect(() => {
103→    if (viewMode !== "flow" || flowData || flowLoading || !sessionId || isSharedView) return;
104→    setFlowLoading(true);
105→    fetchWithToken(`/api/analysis/sessions/${sessionId}/flow`)
106→      .then((res) => (res.ok ? res.json() : null))
107→      .then((data: FlowData | null) => {
108→        if (data) setFlowData(data);
109→      })
110→      .catch(() => {})
111→      .finally(() => setFlowLoading(false));
112→  }, [viewMode, flowData, flowLoading, sessionId, fetchWithToken, isSharedView]);
113→
114→  const main = useMemo(
115→    () => trajectories.find((t) => !t.parent_trajectory_ref) ?? trajectories[0] ?? null,
116→    [trajectories]
117→  );
118→
119→  const subAgents = useMemo(
120→    () =>
121→      trajectories
122→        .filter((t) => !!t.parent_trajectory_ref)
