130→
131→  // Build a map: step_id -> sub-agent trajectories spawned from that step.
132→  // Phase 1 links via observation.subagent_trajectory_ref (explicit linkage).
133→  // Phase 2 places unlinked sub-agents (e.g. compaction) at the
134→  // chronologically correct position using timestamp heuristics.
135→  const subAgentsByStep = useMemo(() => {
136→    const map = new Map<string, Trajectory[]>();
