 1→import { useState, useCallback, useEffect, useRef } from "react";
 2→import { createPortal } from "react-dom";
 3→import { TOOLTIP_OFFSET } from "./chart-constants";
 4→
 5→export interface TooltipState {
 6→  x: number;
 7→  y: number;
 8→  content: string;
 9→}
10→
11→const MAX_WIDTH = 300;
12→
13→export function Tooltip({ state }: { state: TooltipState | null }) {
14→  const ref = useRef<HTMLDivElement>(null);
15→  const [pos, setPos] = useState<{ left: number; top: number }>({
16→    left: 0,
17→    top: 0,
18→  });
19→
20→  useEffect(() => {
21→    if (!state) return;
22→    const el = ref.current;
23→    const elW = el ? el.offsetWidth : MAX_WIDTH;
24→    const elH = el ? el.offsetHeight : 40;
25→    const vw = window.innerWidth;
26→    const vh = window.innerHeight;
27→
28→    let left = state.x + TOOLTIP_OFFSET;
29→    let top = state.y - 8;
30→
31→    // Flip left if overflowing right edge
32→    if (left + elW > vw - 8) {
33→      left = state.x - elW - TOOLTIP_OFFSET;
34→    }
35→    // Clamp top to viewport
36→    if (top + elH > vh - 8) {
37→      top = vh - elH - 8;
38→    }
39→    if (top < 8) {
40→      top = 8;
41→    }
42→
43→    setPos({ left, top });
44→  }, [state]);
45→
46→  if (!state) return null;
47→
48→  return createPortal(
49→    <div
50→      ref={ref}
51→      className="fixed z-[9999] pointer-events-none px-3 py-2.5 rounded-lg bg-zinc-800/95 border border-zinc-600 text-[13px] leading-relaxed text-zinc-100 shadow-2xl whitespace-pre-line"
52→      style={{
53→        left: pos.left,
54→        top: pos.top,
55→        maxWidth: MAX_WIDTH,
56→      }}
57→    >
58→      {state.content}
59→    </div>,
60→    document.body
61→  );
62→}
63→
64→export function useTooltip() {
65→  const [tip, setTip] = useState<TooltipState | null>(null);
66→  const show = useCallback((e: React.MouseEvent, content: string) => {
67→    setTip({ x: e.clientX, y: e.clientY, content });
68→  }, []);
69→  const move = useCallback((e: React.MouseEvent) => {
70→    setTip((prev) => (prev ? { ...prev, x: e.clientX, y: e.clientY } : null));
71→  }, []);
72→  const hide = useCallback(() => setTip(null), []);
73→  return { tip, show, move, hide };
74→}
