from vibelens.stores.local import LocalStore
from vibelens.config import load_settings
from vibelens.analysis.constants import TOOL_CATEGORY_MAP

settings = load_settings()
store = LocalStore(settings)

metas = store.list_metadata()
metas.sort(key=lambda s: s.get('timestamp') or '', reverse=True)

# Analyze error patterns across multiple sessions
print("=== Error & Retry patterns ===")
for m in metas[:20]:
    sid = m['session_id']
    group = store.load(sid)
    if not group:
        continue

    all_steps = []
    for traj in group:
        all_steps.extend(traj.steps)

    # Flatten with error info
    calls_with_errors = []
    for step in all_steps:
        obs_map = {}
        if step.observation:
            for r in step.observation.results:
                if r.source_call_id:
                    is_error = bool(r.extra and r.extra.get('is_error'))
                    obs_map[r.source_call_id] = is_error
        for tc in step.tool_calls:
            cat = TOOL_CATEGORY_MAP.get(tc.function_name, 'other')
            path = ''
            if isinstance(tc.arguments, dict):
                for k in ('file_path', 'path', 'command', 'pattern'):
                    v = tc.arguments.get(k, '')
                    if isinstance(v, str) and v:
                        path = v[:50]
                        break
            calls_with_errors.append({
                'id': tc.tool_call_id or '',
                'name': tc.function_name,
                'cat': cat,
                'is_error': obs_map.get(tc.tool_call_id, False),
                'path': path,
            })

    errors = [c for c in calls_with_errors if c['is_error']]
    if not errors:
        continue

    print(f'\n  Session {sid[:12]} ({len(errors)} errors in {len(calls_with_errors)} calls):')

    # Show error and what follows
    for i, c in enumerate(calls_with_errors):
        if not c['is_error']:
            continue
        next_calls = calls_with_errors[i+1:i+4]
        retry = None
        for nc in next_calls:
            if nc['name'] == c['name']:
                retry = nc
                break

        print(f'    ERR: {c["name"]:12s}({c["path"][:35]})')
        if retry:
            print(f'     -> RETRY: {retry["name"]}({retry["path"][:35]})')
        else:
            nexts = ', '.join(f'{nc["name"]}' for nc in next_calls[:3])
            print(f'     -> NEXT: {nexts}')

