from vibelens.stores.local import LocalStore
from vibelens.config import load_settings
from vibelens.analysis.constants import TOOL_CATEGORY_MAP

settings = load_settings()
store = LocalStore(settings)
metas = store.list_metadata()

# Analyze EVERY session for error retry and common patterns
total_errors = 0
total_bash_sequences = 0
total_write_then_shell = 0
total_same_file_multi_edit = 0

for m in metas:
    sid = m['session_id']
    group = store.load(sid)
    if not group:
        continue

    all_steps = []
    for traj in group:
        all_steps.extend(traj.steps)

    calls = []
    for step in all_steps:
        obs_map = {}
        if step.observation:
            for r in step.observation.results:
                if r.source_call_id:
                    is_error = bool(r.extra and r.extra.get('is_error'))
                    obs_map[r.source_call_id] = is_error
        for tc in step.tool_calls:
            cat = TOOL_CATEGORY_MAP.get(tc.function_name, 'other')
            path = ''
            cmd = ''
            if isinstance(tc.arguments, dict):
                path = tc.arguments.get('file_path', '') or tc.arguments.get('path', '') or ''
                cmd = tc.arguments.get('command', '') or ''
            calls.append({
                'id': tc.tool_call_id or '',
                'name': tc.function_name,
                'cat': cat,
                'is_error': obs_map.get(tc.tool_call_id, False),
                'path': path[:80] if isinstance(path, str) else '',
                'cmd': cmd[:60] if isinstance(cmd, str) else '',
            })

    for c in calls:
        if c['is_error']:
            total_errors += 1

    # Pattern: Write/Edit → Bash (test) - common edit-test loop
    for i in range(len(calls) - 1):
        if calls[i]['cat'] == 'file_write' and calls[i+1]['cat'] == 'shell':
            total_write_then_shell += 1

    # Pattern: Bash → Bash (sequential shell)
    for i in range(len(calls) - 1):
        if calls[i]['cat'] == 'shell' and calls[i+1]['cat'] == 'shell':
            total_bash_sequences += 1

    # Pattern: multiple edits to same file
    file_edit_counts = {}
    for c in calls:
        if c['cat'] == 'file_write' and c['path']:
            file_edit_counts[c['path']] = file_edit_counts.get(c['path'], 0) + 1
    for path, count in file_edit_counts.items():
        if count > 1:
            total_same_file_multi_edit += 1

print(f'Total sessions scanned: {len(metas)}')
print(f'Total errors across all sessions: {total_errors}')
print(f'Write→Shell sequences (edit-test loops): {total_write_then_shell}')
print(f'Shell→Shell sequences: {total_bash_sequences}')
print(f'Files edited multiple times: {total_same_file_multi_edit}')

