602→function MetaPill({
603→  icon,
604→  label,
605→  color,
606→  tooltip,
607→}: {
608→  icon: React.ReactNode;
609→  label: string;
610→  color: string;
611→  tooltip?: string;
612→}) {
613→  const [show, setShow] = useState(false);
