615→
616→  return (
617→    <span
618→      ref={ref}
619→      className={`relative inline-flex items-center gap-1 px-2 py-0.5 rounded-full bg-zinc-800 border border-zinc-700/50 text-[11px] ${color}`}
620→      onMouseEnter={() => setShow(true)}
621→      onMouseLeave={() => setShow(false)}
622→    >
623→      {icon}
