625→      {tooltip && show && (
626→        <span className="absolute left-0 top-full mt-1.5 z-[100] px-2.5 py-1.5 rounded-md bg-zinc-950 border border-zinc-700 text-[11px] text-zinc-300 whitespace-nowrap shadow-lg pointer-events-none">
627→          {tooltip}
628→        </span>
629→      )}
630→    </span>
631→  );
632→}
