684→function formatCreatedTime(timestamp: string): string {
685→  const date = new Date(timestamp);
686→  if (isNaN(date.getTime())) return timestamp;
687→  return date.toLocaleString(undefined, {
688→    month: "short",
689→    day: "numeric",
690→    hour: "2-digit",
691→    minute: "2-digit",
692→  });
693→}
