  1→/**
  2→ * FlowDiagram — DOM/CSS conversation flow visualization.
  3→ *
  4→ * Renders a vertical flow of user→agent→tool cards grouped by phase.
  5→ * Tool calls are shown as compact colored chips inside agent cards,
  6→ * eliminating messy fan-out arrows. Dependencies are revealed on hover
  7→ * via highlight rings on related tools.
  8→ */
  9→
 10→import { useState, useMemo, useCallback } from "react";
 11→import type { Step, FlowData } from "../../types";
 12→import { useTooltip, Tooltip, type TooltipContent } from "../analysis/tooltip";
 13→import {
 14→  computeFlow,
 15→  type FlowPhaseGroup,
 16→  type FlowToolChip,
 17→} from "./flow-layout";
 18→
 19→interface FlowDiagramProps {
 20→  steps: Step[];
 21→  flowData: FlowData;
 22→}
 23→
 24→const CATEGORY_STYLE: Record<string, { bg: string; ring: string; text: string; label: string }> = {
 25→  file_read: { bg: "bg-blue-500/20", ring: "ring-blue-400/60", text: "text-blue-300", label: "read" },
 26→  file_write: { bg: "bg-emerald-500/20", ring: "ring-emerald-400/60", text: "text-emerald-300", label: "write" },
 27→  shell: { bg: "bg-amber-500/20", ring: "ring-amber-400/60", text: "text-amber-300", label: "shell" },
 28→  search: { bg: "bg-sky-500/20", ring: "ring-sky-400/60", text: "text-sky-300", label: "search" },
 29→  web: { bg: "bg-orange-500/20", ring: "ring-orange-400/60", text: "text-orange-300", label: "web" },
 30→  agent: { bg: "bg-violet-500/20", ring: "ring-violet-400/60", text: "text-violet-300", label: "agent" },
 31→  task: { bg: "bg-rose-500/20", ring: "ring-rose-400/60", text: "text-rose-300", label: "task" },
 32→  other: { bg: "bg-zinc-500/20", ring: "ring-zinc-400/60", text: "text-zinc-400", label: "other" },
 33→};
 34→
 35→const PHASE_STYLE: Record<string, { border: string; label: string; dot: string; bg: string }> = {
 36→  exploration: { border: "border-l-blue-400", label: "text-blue-400", dot: "bg-blue-400", bg: "bg-blue-500/[0.03]" },
 37→  implementation: { border: "border-l-emerald-400", label: "text-emerald-400", dot: "bg-emerald-400", bg: "bg-emerald-500/[0.03]" },
 38→  debugging: { border: "border-l-red-400", label: "text-red-400", dot: "bg-red-400", bg: "bg-red-500/[0.03]" },
 39→  verification: { border: "border-l-amber-400", label: "text-amber-400", dot: "bg-amber-400", bg: "bg-amber-500/[0.03]" },
 40→  planning: { border: "border-l-violet-400", label: "text-violet-400", dot: "bg-violet-400", bg: "bg-violet-500/[0.03]" },
 41→  mixed: { border: "border-l-zinc-500", label: "text-zinc-400", dot: "bg-zinc-500", bg: "bg-zinc-500/[0.02]" },
 42→};
 43→
 44→const RELATION_LABELS: Record<string, string> = {
 45→  read_before_write: "read \u2192 write",
 46→  search_then_read: "search \u2192 read",
 47→  write_then_test: "edit \u2192 test",
 48→  multi_edit: "re-edit",
 49→  error_retry: "retry",
 50→};
 51→
 52→export function FlowDiagram({ steps, flowData }: FlowDiagramProps) {
 53→  const { tip, show, move, hide } = useTooltip();
 54→  const [hoveredToolId, setHoveredToolId] = useState<string | null>(null);
 55→
 56→  const result = useMemo(
 57→    () => computeFlow(steps, flowData.tool_graph, flowData.phase_segments),
 58→    [steps, flowData]
 59→  );
 60→
 61→  // Bidirectional dependency lookup for hover highlighting
 62→  const relatedTools = useMemo(() => {
 63→    const map = new Map<string, Set<string>>();
 64→    for (const [sourceId, deps] of result.dependencies) {
 65→      for (const dep of deps) {
 66→        if (!map.has(sourceId)) map.set(sourceId, new Set());
 67→        map.get(sourceId)!.add(dep.targetToolCallId);
 68→        if (!map.has(dep.targetToolCallId)) map.set(dep.targetToolCallId, new Set());
 69→        map.get(dep.targetToolCallId)!.add(sourceId);
 70→      }
 71→    }
 72→    return map;
 73→  }, [result.dependencies]);
 74→
 75→  // Dependency label for a highlighted tool
 76→  const depLabels = useMemo(() => {
 77→    const map = new Map<string, string>();
 78→    for (const [sourceId, deps] of result.dependencies) {
 79→      for (const dep of deps) {
 80→        const label = RELATION_LABELS[dep.relation] || dep.relation;
 81→        map.set(`${sourceId}->${dep.targetToolCallId}`, label);
 82→        map.set(`${dep.targetToolCallId}->${sourceId}`, label);
 83→      }
 84→    }
 85→    return map;
 86→  }, [result.dependencies]);
 87→
 88→  const isHighlighted = useCallback(
 89→    (toolCallId: string): boolean => {
 90→      if (!hoveredToolId) return false;
 91→      if (toolCallId === hoveredToolId) return true;
 92→      return relatedTools.get(hoveredToolId)?.has(toolCallId) || false;
 93→    },
 94→    [hoveredToolId, relatedTools]
 95→  );
 96→
 97→  const getDepLabel = useCallback(
 98→    (toolCallId: string): string | null => {
 99→      if (!hoveredToolId || toolCallId === hoveredToolId) return null;
100→      return depLabels.get(`${hoveredToolId}->${toolCallId}`) || null;
101→    },
102→    [hoveredToolId, depLabels]
103→  );
104→
105→  return (
106→    <div className="max-w-3xl mx-auto pb-8">
107→      {result.phases.map((phase, phaseIdx) => (
108→        <div key={phaseIdx} id={`flow-phase-${phaseIdx}`}>
109→          <PhaseSection phase={phase}>
110→            {phase.cards.map((card, cardIdx) => (
111→              <div key={card.data.id}>
112→                {cardIdx > 0 && <Connector />}
113→                {card.type === "user" ? (
114→                  <UserCard
115→                    label={card.data.label}
116→                    detail={card.data.detail}
117→                    onHover={show}
118→                    onMove={move}
119→                    onLeave={hide}
120→                  />
121→                ) : (
122→                  <AgentCard
123→                    label={card.data.label}
124→                    detail={card.data.detail}
125→                    tools={card.data.tools}
126→                    hoveredToolId={hoveredToolId}
127→                    onToolEnter={setHoveredToolId}
128→                    onToolLeave={() => setHoveredToolId(null)}
129→                    isHighlighted={isHighlighted}
130→                    getDepLabel={getDepLabel}
131→                    onHover={show}
132→                    onMove={move}
133→                    onLeave={hide}
134→                  />
135→                )}
136→              </div>
137→            ))}
138→          </PhaseSection>
139→          {/* Connector between phase sections */}
140→          {phaseIdx < result.phases.length - 1 && (
141→            <div className="flex items-center pl-6 py-1">
142→              <div className="flex flex-col items-center">
143→                <div className="w-px h-2 bg-zinc-700/30" />
144→                <div className="w-1 h-1 rounded-full bg-zinc-600/40" />
145→                <div className="w-px h-2 bg-zinc-700/30" />
146→              </div>
147→            </div>
148→          )}
149→        </div>
150→      ))}
151→      <Tooltip state={tip} />
152→    </div>
153→  );
154→}
155→
156→function PhaseSection({
157→  phase,
158→  children,
159→}: {
160→  phase: FlowPhaseGroup;
161→  children: React.ReactNode;
162→}) {
163→  const style = PHASE_STYLE[phase.phase] || PHASE_STYLE.mixed;
164→
165→  return (
166→    <div className={`rounded-lg ${style.bg}`}>
167→      <div className={`border-l-[3px] ${style.border} pl-5 pr-3 py-4`}>
168→        {/* Phase header */}
169→        <div className="flex items-center gap-2.5 mb-4">
170→          <span className={`w-2.5 h-2.5 rounded-full ${style.dot} ring-2 ring-current/10`} />
171→          <span className={`text-[11px] font-bold uppercase tracking-[0.14em] ${style.label}`}>
172→            {phase.phase}
173→          </span>
174→          <span className="text-[10px] text-zinc-500 font-medium">
175→            {phase.cards.length} step{phase.cards.length !== 1 ? "s" : ""}
176→          </span>
177→        </div>
178→        <div>{children}</div>
179→      </div>
180→    </div>
181→  );
182→}
183→
184→function Connector() {
185→  return (
186→    <div className="flex items-center justify-center py-1.5">
187→      <div className="flex flex-col items-center">
188→        <div className="w-px h-2.5 bg-zinc-700/40" />
189→        <div className="w-[5px] h-[5px] rounded-full border border-zinc-600/60 bg-zinc-800" />
190→        <div className="w-px h-2.5 bg-zinc-700/40" />
191→      </div>
192→    </div>
193→  );
194→}
