230→function AgentCard({
231→  label,
232→  detail,
233→  tools,
234→  hoveredToolId,
235→  onToolEnter,
236→  onToolLeave,
237→  isHighlighted,
238→  getDepLabel,
239→  onHover,
240→  onMove,
241→  onLeave,
242→}: {
243→  label: string;
244→  detail: string;
245→  tools: FlowToolChip[];
246→  hoveredToolId: string | null;
247→  onToolEnter: (id: string) => void;
248→  onToolLeave: () => void;
249→  isHighlighted: (toolCallId: string) => boolean;
250→  getDepLabel: (toolCallId: string) => string | null;
251→  onHover: (e: React.MouseEvent, content: TooltipContent) => void;
252→  onMove: (e: React.MouseEvent) => void;
253→  onLeave: () => void;
254→}) {
255→  // Group tools by category for summary display
256→  const grouped = useMemo(() => {
257→    const map = new Map<string, FlowToolChip[]>();
258→    for (const tool of tools) {
259→      const list = map.get(tool.category) || [];
260→      list.push(tool);
261→      map.set(tool.category, list);
262→    }
263→    const order = ["file_read", "search", "file_write", "shell", "web", "agent", "task", "other"];
264→    return [...map.entries()].sort(
265→      ([a], [b]) => (order.indexOf(a) === -1 ? 99 : order.indexOf(a)) - (order.indexOf(b) === -1 ? 99 : order.indexOf(b))
266→    );
267→  }, [tools]);
268→
269→  return (
270→    <div className="rounded-lg border border-cyan-500/20 bg-cyan-950/20 hover:border-cyan-400/35 transition-colors">
271→      {/* Agent message */}
272→      <div
273→        className="px-4 py-3 flex items-start gap-3"
274→        onMouseEnter={(e) => onHover(e, detail)}
275→        onMouseMove={onMove}
276→        onMouseLeave={onLeave}
277→      >
278→        <span className="shrink-0 mt-0.5 w-6 h-6 rounded-md bg-cyan-500/20 border border-cyan-400/15 flex items-center justify-center">
279→          <svg className="w-3 h-3 text-cyan-300" viewBox="0 0 16 16" fill="currentColor">
280→            <path d="M6 12.5a.5.5 0 0 1 .5-.5h3a.5.5 0 0 1 0 1h-3a.5.5 0 0 1-.5-.5zM3 8.062C3 6.76 4.235 5.765 5.53 5.886a26.58 26.58 0 0 0 4.94 0C11.765 5.765 13 6.76 13 8.062v1.157a.933.933 0 0 1-.765.935c-.845.147-2.34.346-4.235.346-1.895 0-3.39-.2-4.235-.346A.933.933 0 0 1 3 9.219V8.062zm4.542-.827a.25.25 0 0 0-.217.068l-.92.9a25.14 25.14 0 0 1-1.871-.183.25.25 0 0 0-.068.495c.55.076 1.232.149 2.02.193a.25.25 0 0 0 .189-.071l.754-.736.847 1.71a.25.25 0 0 0 .404.062l.932-.97a25.286 25.286 0 0 0 1.922-.188.25.25 0 0 0-.068-.495c-.538.074-1.207.145-1.98.189a.25.25 0 0 0-.166.076l-.754.785-.842-1.7a.25.25 0 0 0-.182-.135z"/>
281→            <path d="M8.5 1.866a1 1 0 1 0-1 0V3h-2A4.5 4.5 0 0 0 1 7.5V8a1 1 0 0 0-1 1v2a1 1 0 0 0 1 1v1a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2v-1a1 1 0 0 0 1-1V9a1 1 0 0 0-1-1v-.5A4.5 4.5 0 0 0 10.5 3h-2V1.866zM14 7.5V13a1 1 0 0 1-1 1H3a1 1 0 0 1-1-1V7.5A3.5 3.5 0 0 1 5.5 4h5A3.5 3.5 0 0 1 14 7.5z"/>
282→          </svg>
283→        </span>
284→        <p className="text-[13px] leading-relaxed text-cyan-100 min-w-0 break-words">
285→          {label}
286→        </p>
287→      </div>
288→
289→      {/* Tool calls section */}
290→      {tools.length > 0 && (
291→        <div className="border-t border-cyan-500/10 mx-3 px-1 py-2.5">
292→          {/* Header with count and category breakdown */}
293→          <div className="flex items-center gap-1.5 mb-2 px-1">
294→            <span className="text-[10px] font-semibold text-zinc-400 uppercase tracking-wider">
295→              {tools.length} tool{tools.length !== 1 ? "s" : ""}
296→            </span>
297→            <span className="text-zinc-700 text-[10px]">{"·"}</span>
298→            <div className="flex gap-1.5">
299→              {grouped.map(([cat, items]) => {
300→                const catStyle = CATEGORY_STYLE[cat] || CATEGORY_STYLE.other;
301→                return (
302→                  <span
303→                    key={cat}
304→                    className={`inline-flex items-center gap-1 text-[10px] ${catStyle.text}`}
305→                    title={`${items.length} ${cat.replace(/_/g, " ")}`}
306→                  >
307→                    <span className={`w-2 h-2 rounded-sm ${catStyle.bg} border border-current/20`} />
308→                    <span className="opacity-80">{catStyle.label}</span>
309→                    <span className="font-mono font-semibold">{items.length}</span>
310→                  </span>
