  1→/**
  2→ * Flow layout engine — converts Steps + FlowData into structured card data.
  3→ *
  4→ * Produces phase-grouped cards (user prompts + agent responses with embedded
  5→ * tool chips) and a dependency map for hover highlighting. No x/y positioning
  6→ * needed — the FlowDiagram component uses DOM/CSS layout.
  7→ */
  8→
  9→import type { Step, ToolDependencyGraph, PhaseSegment } from "../../types";
 10→import { extractMessageText } from "../../utils";
 11→
 12→export interface FlowToolChip {
 13→  id: string;
 14→  name: string;
 15→  category: string;
 16→  detail: string;
 17→  toolCallId: string;
 18→}
 19→
 20→export interface FlowAgentCardData {
 21→  id: string;
 22→  label: string;
 23→  detail: string;
 24→  stepIndex: number;
 25→  tools: FlowToolChip[];
 26→}
 27→
 28→export interface FlowUserCardData {
 29→  id: string;
 30→  label: string;
 31→  detail: string;
 32→  stepIndex: number;
 33→}
 34→
 35→export type FlowCard =
 36→  | { type: "user"; data: FlowUserCardData }
 37→  | { type: "agent"; data: FlowAgentCardData };
 38→
 39→export interface FlowPhaseGroup {
 40→  phase: string;
 41→  cards: FlowCard[];
 42→  toolCount: number;
 43→  dominantCategory: string;
 44→}
 45→
 46→export interface ToolRelation {
 47→  targetToolCallId: string;
 48→  relation: string;
 49→  sharedResource?: string;
 50→}
 51→
 52→export interface FlowResult {
 53→  phases: FlowPhaseGroup[];
 54→  dependencies: Map<string, ToolRelation[]>;
 55→}
 56→
 57→const LABEL_MAX_LENGTH = 120;
 58→
 59→const TOOL_CATEGORY_MAP: Record<string, string> = {
 60→  Read: "file_read",
 61→  read_file: "file_read",
 62→  cat: "file_read",
 63→  Glob: "search",
 64→  glob: "search",
 65→  Grep: "search",
 66→  grep: "search",
 67→  find: "search",
 68→  Edit: "file_write",
