 91→function truncateLabel(text: string, max: number): string {
 92→  if (text.length <= max) return text;
 93→  return text.slice(0, max - 1) + "\u2026";
 94→}
 95→
 96→function formatToolArgs(args: unknown): string {
 97→  if (!args) return "";
 98→  if (typeof args === "string") return args.slice(0, 300);
 99→  try {
100→    return JSON.stringify(args, null, 2).slice(0, 400);
101→  } catch {
102→    return String(args).slice(0, 300);
103→  }
104→}
105→
106→/** Build structured flow data from steps and analysis results. */
107→export function computeFlow(
108→  steps: Step[],
109→  toolGraph: ToolDependencyGraph | null,
110→  phases: PhaseSegment[]
111→): FlowResult {
112→  const cards = buildCards(steps);
113→  const phaseGroups = assignCardsToPhases(cards, phases);
114→  const dependencies = buildDependencyMap(toolGraph);
115→  return { phases: phaseGroups, dependencies };
116→}
117→
118→function buildCards(steps: Step[]): FlowCard[] {
119→  const cards: FlowCard[] = [];
120→  let globalStepIdx = 0;
121→
122→  for (const step of steps) {
123→    const stepIdx = globalStepIdx++;
124→
125→    if (step.source === "user") {
126→      const text = extractMessageText(step.message);
127→      if (!text) continue;
128→      cards.push({
129→        type: "user",
130→        data: {
131→          id: `user-${step.step_id}`,
132→          label: truncateLabel(text, LABEL_MAX_LENGTH),
133→          detail: text,
134→          stepIndex: stepIdx,
135→        },
136→      });
137→    }
138→
139→    if (step.source === "agent") {
140→      const text = extractMessageText(step.message);
141→      const hasTools = step.tool_calls.length > 0;
142→      if (!text && !hasTools) continue;
143→
144→      const tools: FlowToolChip[] = step.tool_calls.map((tc) => ({
145→        id: `tool-${tc.tool_call_id}`,
146→        name: tc.function_name,
147→        category: TOOL_CATEGORY_MAP[tc.function_name] || "other",
148→        detail: `${tc.function_name}\n${formatToolArgs(tc.arguments)}`,
149→        toolCallId: tc.tool_call_id,
150→      }));
151→
152→      cards.push({
153→        type: "agent",
154→        data: {
155→          id: `agent-${step.step_id}`,
156→          label: text ? truncateLabel(text, LABEL_MAX_LENGTH) : "Agent processing\u2026",
157→          detail: text || "(tool calls only)",
158→          stepIndex: stepIdx,
159→          tools,
160→        },
161→      });
162→    }
163→  }
164→
165→  return cards;
166→}
167→
168→function computePhaseSummary(cards: FlowCard[]): { toolCount: number; dominantCategory: string } {
169→  const categoryCounts = new Map<string, number>();
170→  let toolCount = 0;
171→  for (const card of cards) {
172→    if (card.type === "agent") {
173→      for (const tool of card.data.tools) {
174→        toolCount++;
175→        categoryCounts.set(tool.category, (categoryCounts.get(tool.category) || 0) + 1);
176→      }
177→    }
178→  }
179→  let dominantCategory = "other";
180→  let maxCount = 0;
181→  for (const [cat, count] of categoryCounts) {
182→    if (count > maxCount) {
183→      maxCount = count;
184→      dominantCategory = cat;
185→    }
186→  }
187→  return { toolCount, dominantCategory };
188→}
189→
190→function assignCardsToPhases(
191→  cards: FlowCard[],
192→  phases: PhaseSegment[]
193→): FlowPhaseGroup[] {
194→  if (phases.length === 0) {
195→    if (cards.length === 0) return [];
196→    const { toolCount, dominantCategory } = computePhaseSummary(cards);
197→    return [{ phase: "mixed", cards, toolCount, dominantCategory }];
198→  }
199→
200→  const groups: FlowPhaseGroup[] = [];
201→  const assignedIndices = new Set<number>();
202→
203→  for (const seg of phases) {
204→    const segCards = cards.filter((c) => {
205→      const idx = c.data.stepIndex;
206→      return idx >= seg.start_index && idx <= seg.end_index;
207→    });
208→    if (segCards.length > 0) {
209→      const { toolCount, dominantCategory } = computePhaseSummary(segCards);
210→      groups.push({ phase: seg.phase, cards: segCards, toolCount, dominantCategory });
211→      segCards.forEach((c) => assignedIndices.add(c.data.stepIndex));
212→    }
213→  }
214→
215→  // Unassigned cards go into "mixed"
216→  const uncovered = cards.filter((c) => !assignedIndices.has(c.data.stepIndex));
217→  if (uncovered.length > 0) {
218→    const { toolCount, dominantCategory } = computePhaseSummary(uncovered);
219→    groups.push({ phase: "mixed", cards: uncovered, toolCount, dominantCategory });
220→  }
221→
222→  return groups;
223→}
224→
225→function buildDependencyMap(
226→  toolGraph: ToolDependencyGraph | null
227→): Map<string, ToolRelation[]> {
228→  const map = new Map<string, ToolRelation[]>();
229→  if (!toolGraph) return map;
230→
231→  for (const edge of toolGraph.edges) {
232→    if (edge.relation === "sequential") continue;
233→    const existing = map.get(edge.source_tool_call_id) || [];
234→    existing.push({
235→      targetToolCallId: edge.target_tool_call_id,
236→      relation: edge.relation,
237→      sharedResource: edge.shared_resource || undefined,
238→    });
239→    map.set(edge.source_tool_call_id, existing);
240→  }
241→
242→  return map;
243→}
