 1→import { useState, useCallback, useEffect, useRef } from "react";
 2→import { createPortal } from "react-dom";
 3→import { TOOLTIP_OFFSET } from "./chart-constants";
 4→
 5→export type TooltipContent = string | React.ReactNode;
 6→
 7→export interface TooltipState {
 8→  x: number;
 9→  y: number;
10→  content: TooltipContent;
11→}
12→
13→const MAX_WIDTH = 300;
14→const MAX_WIDTH_WIDE = 480;
15→
16→export function Tooltip({ state }: { state: TooltipState | null }) {
17→  const ref = useRef<HTMLDivElement>(null);
18→  const [pos, setPos] = useState<{ left: number; top: number }>({
19→    left: 0,
20→    top: 0,
21→  });
22→
23→  const isRichContent = state != null && typeof state.content !== "string";
24→  const maxW = isRichContent ? MAX_WIDTH_WIDE : MAX_WIDTH;
25→
26→  useEffect(() => {
27→    if (!state) return;
28→    const el = ref.current;
29→    const elW = el ? el.offsetWidth : maxW;
30→    const elH = el ? el.offsetHeight : 40;
31→    const vw = window.innerWidth;
32→    const vh = window.innerHeight;
33→
34→    let left = state.x + TOOLTIP_OFFSET;
35→    let top = state.y - 8;
36→
37→    // Flip left if overflowing right edge
38→    if (left + elW > vw - 8) {
39→      left = state.x - elW - TOOLTIP_OFFSET;
40→    }
41→    // Clamp top to viewport
42→    if (top + elH > vh - 8) {
43→      top = vh - elH - 8;
44→    }
45→    if (top < 8) {
46→      top = 8;
47→    }
48→
49→    setPos({ left, top });
50→  }, [state, maxW]);
51→
52→  if (!state) return null;
53→
54→  return createPortal(
55→    <div
56→      ref={ref}
57→      className={`fixed z-[9999] pointer-events-none px-3 py-2.5 rounded-lg bg-zinc-800/95 border border-zinc-600 text-[13px] leading-relaxed text-zinc-100 shadow-2xl ${
58→        isRichContent ? "whitespace-pre-wrap" : "whitespace-pre-line"
59→      }`}
60→      style={{
61→        left: pos.left,
62→        top: pos.top,
63→        maxWidth: maxW,
64→      }}
65→    >
66→      {state.content}
67→    </div>,
68→    document.body
69→  );
70→}
71→
72→export function useTooltip() {
73→  const [tip, setTip] = useState<TooltipState | null>(null);
74→  const show = useCallback((e: React.MouseEvent, content: TooltipContent) => {
75→    setTip({ x: e.clientX, y: e.clientY, content });
76→  }, []);
77→  const move = useCallback((e: React.MouseEvent) => {
78→    setTip((prev) => (prev ? { ...prev, x: e.clientX, y: e.clientY } : null));
79→  }, []);
80→  const hide = useCallback(() => setTip(null), []);
81→  return { tip, show, move, hide };
82→}
