python3 << 'EOF'
import json
path = "/Users/user/.claude/projects/-Users-user--claude-skills/d7a6dae4-2ddc-4185-91a3-c7a09c2ca785.jsonl"

# Collect Agent tool_use IDs
spawn_ids = set()
# Collect their tool_results
with open(path) as f:
    for line in f:
        d = json.loads(line.strip())
        if d.get("type") == "assistant":
            msg = d.get("message", {})
            content = msg.get("content", [])
            if isinstance(content, list):
                for b in content:
                    if isinstance(b, dict) and b.get("type") == "tool_use" and b.get("name") in ("Agent", "Task"):
                        spawn_ids.add(b.get("id", ""))

# Now find tool_results for those IDs and look for agentId
import re
agent_id_pattern = re.compile(r"agentId:\s*([a-f0-9]+)")
found_agents = {}
with open(path) as f:
    for line in f:
        d = json.loads(line.strip())
        if d.get("type") != "user":
            continue
        msg = d.get("message", {})
        content = msg.get("content", [])
        if not isinstance(content, list):
            continue
        for b in content:
            if not isinstance(b, dict) or b.get("type") != "tool_result":
                continue
            tc_id = b.get("tool_use_id", "")
            if tc_id not in spawn_ids:
                continue
            result_content = b.get("content", "")
            if isinstance(result_content, list):
                result_content = " ".join(bl.get("text", "") for bl in result_content if isinstance(bl, dict))
            result_content = str(result_content)
            m = agent_id_pattern.search(result_content)
            if m:
                found_agents[m.group(1)] = tc_id
            else:
                print(f"tool_result for {tc_id}: NO agentId match, content[:200]={result_content[:200]}")

print(f"\nFound {len(found_agents)} agent IDs in tool results")
print(f"Agent tool_use count: {len(spawn_ids)}")
# Check if a052f4aadef4dbe6c is in the found set
target = "a052f4aadef4dbe6c"
if target in found_agents:
    print(f"Target {target} FOUND in spawn map")
else:
    print(f"Target {target} NOT FOUND in spawn map")
EOF

